/** Get vocabulary by ID */
export function getVocabById(id: string): VocabularyItem | undefined {
  return VOCABULARY.find((v) => v.id === id);
}

/** Get all vocabulary for a topic */
export function getVocabByTopic(topic: VocabularyItem["topic"]): VocabularyItem[] {
  return VOCABULARY.filter((v) => v.topic === topic);
}
